xf:group.script:
	/**
	* //property handling
	* $w.log("id:" + options.id);
	* $w.log("date:" + options.date);
	* $w.log("ref:" + options.ref);
	*
	* //event trigger
	* udc_obj.trigger("onBtnCalendarClick"); 
	*/

	//초기 수행함수 
	this.initQuarterCalendar = function() {
		this.today = "";
		this.selectedDate = "";

		var tmpDate = new Date();
		var hours = tmpDate.getHours();
		var minutes = tmpDate.getMinutes();
		var seconds = tmpDate.getSeconds();

		if (parseInt(hours) > 12) {
			hours = parseInt(hours) - 12;
			meridiem.setValue("PM");
		} else {
			meridiem.setValue("AM");
		}
		// if(hours < 10) {
			// hours = "0" + hours;
		// }
		hour.setValue(hours);
		minute.setValue(minutes);
		second.setValue(seconds);

		// udc의 초기 설정값
		if (ibx_Date.getValue() == "" && options.date != undefined) {
			ibx_Date.setValue(options.date);
		}
		// ref 설젇 
		if (options.ref != "") {
			ibx_Date.setRef(options.ref);
		}
		this.changeTime(ibx_Date.getValue());
	};

	scwin.displayTimePicker = function(value) {
			if(value.length < 2){
				value = "0"+value;
			}
		return value;
	};

	udc_obj.changeMeridiem = function() {
		if (meridiem.getValue() == "AM") {
			meridiem.setValue("PM");
		} else {
			meridiem.setValue("AM");
		}
	};

this.changeTime = function(strDate) {
	strDate = strDate.replaceAll(":", "");
	if (strDate.length > 5) {
		var time = "";
		var hours = strDate.substr(0, 2);
		var minutes = strDate.substr(2, 2);
		var seconds = strDate.substr(4, 2);
		var meridiemStr = strDate.substr(6, 2);

		if (hours > 24) {
			alert("잘못된 시간형식입니다.");
			hour.setValue("01");
			minute.setValue("01");
			second.setValue("01");
			meridiem.setValue("AM");
			ibx_Date.setValue("01" + ":" + "01" + ":" + "01" + ":" + "AM");
			return false;
		}
		if (minutes > 59) {
			alert("잘못된 분형식입니다.");
			hour.setValue("01");
			minute.setValue("01");
			second.setValue("01");
			meridiem.setValue("AM");
			ibx_Date.setValue("01" + ":" + "01" + ":" + "01" + ":" + "AM");
			return false;
		}
		if (seconds > 59) {
			alert("잘못된 초형식입니다.");
			hour.setValue("01");
			minute.setValue("01");
			second.setValue("01");
			meridiem.setValue("AM");
			ibx_Date.setValue("01" + ":" + "01" + ":" + "01" + ":" + "AM");
			return false;
		}
		if (meridiemStr == "AM" || meridiemStr == "PM") {
				if (parseInt(strDate.substr(0, 2)) > 12) {
					hours = parseInt(strDate.substr(0, 2)) - 12;
				}
				meridiem.setValue(meridiemStr);
		} else {
			if (parseInt(strDate.substr(0, 2)) > 12) {
				hours = parseInt(strDate.substr(0, 2)) - 12;
				meridiem.setValue("PM");
				meridiemStr="PM";
			} else {
				meridiem.setValue("AM");
				meridiemStr="AM";
			}
		}

		hours = scwin.displayTimePicker(hours + "");
		ibx_Date.setValue(hours + ":" + minutes + ":" + seconds + ":" + meridiemStr);
		hour.setValue(hours);
		minute.setValue(minutes);
		second.setValue(seconds);
		// meridiem.setValue(meridiemStr);
	}
};

this.showTimePicker = function() {
	if (div_time.getStyle("display") == "none") {
		div_time.setStyle("display", "");
	} else {
		div_time.setStyle("display", "none");
	}
};

// 확인 버튼 클릭시 
this.clickTimePicker = function() {
	var hourStr = hour.getValue();
	var minuteStr = minute.getValue();
	var secondStr = second.getValue();

	if (hourStr.length < 2) {
		hourStr = "0" + hourStr;
	}
	if (minuteStr.length < 2) {
		minuteStr = "0" + minuteStr;
	}
	if (secondStr.length < 2) {
		secondStr = "0" + secondStr;
	}

	var time = hourStr + ":" + minuteStr + ":" + secondStr + ":" + meridiem.getValue();

	ibx_Date.setValue(time);

	div_time.setStyle("display", "none");
};

udc_obj.getDate = function() {
	if (ibx_Date.getValue() == "") {
		return null;
	} else {
		return ibx_Date.getValue();
	}
};

udc_obj.setDate = function(strDate) {
	ibx_Date.setValue(strDate);
};

// 초기 실행함수 수행
this.initQuarterCalendar();
